import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate("/login");
  };

  return (
    <nav style={{
      width: "100%",
      background: "#ffffff",
      borderBottom: "1px solid #e5e7eb",
      position: "sticky",
      top: 0,
      zIndex: 1000
    }}>
      <div style={{
        maxWidth: "1100px",
        margin: "0 auto",
        padding: "14px 20px",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center"
      }}>
        
        {/* LOGO */}
        <Link to="/" style={{
          fontSize: "20px",
          fontWeight: "600",
          color: "#111827"
        }}>
          SubManager
        </Link>

        {/* RIGHT SIDE */}
        <div style={{
          display: "flex",
          alignItems: "center",
          gap: "18px"
        }}>
          {user ? (
            <>
              <Link to="/tasks" style={{ color: "#4b5563" }}>
                Subscriptions
              </Link>

              <Link to="/profile" style={{ color: "#4b5563" }}>
                Profile
              </Link>

              {user.role === "admin" && (
                <Link to="/admin" style={{
                  color: "#4f46e5",
                  fontWeight: "500"
                }}>
                  Admin
                </Link>
              )}

              {/* ROLE BADGE */}
              <span style={{
                background: "#eef2ff",
                color: "#4f46e5",
                padding: "4px 10px",
                borderRadius: "999px",
                fontSize: "12px",
                fontWeight: "500"
              }}>
                {user.role}
              </span>

              {/* LOGOUT */}
              <button
                onClick={handleLogout}
                style={{
                  background: "#ef4444",
                  color: "white",
                  padding: "6px 12px",
                  borderRadius: "6px",
                  border: "none",
                  cursor: "pointer"
                }}
              >
                Logout
              </button>
            </>
          ) : (
            <>
              <Link to="/login" style={{ color: "#4b5563" }}>
                Login
              </Link>

              <Link to="/register" style={{
                background: "#4f46e5",
                color: "white",
                padding: "6px 12px",
                borderRadius: "6px"
              }}>
                Register
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
